class Solution {
    public int findMinimumOperations(String s1, String s2, String s3) {
        int m = s1.length(), n = s2.length(), o = s3.length();
        int[][] dp = new int[m + 1][n + 1][o + 1];
        for (int i = 0; i <= m; i++) {
            for (int j = 0; j <= n; j++) {
                for (int k = 0; k <= o; k++) {
                    if (i == 0 || j == 0 || k == 0) {
                        dp[i][j][k] = i + j + k;
                    } else {
                        if (s1.charAt(i - 1) == s2.charAt(j - 1) && s1.charAt(i - 1) == s3.charAt(k - 1)) {
                            dp[i][j][k] = dp[i - 1][j - 1][k - 1];
                        } else {
                            dp[i][j][k] = 1 + Math.min(Math.min(dp[i - 1][j][k], dp[i][j - 1][k]), dp[i][j][k - 1]);
                        }
                    }
                }
            }
        }
        return dp[m][n][o] == m + n + o ? -1 : dp[m][n][o];
    }
}
